(window.webpackJsonp=window.webpackJsonp||[]).push([[1241],{1186:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> totalHammingDistance = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;<span class=\\"hljs-number\\">32</span>;i++){\\n    <span class=\\"hljs-keyword\\">let</span> one=<span class=\\"hljs-number\\">0</span>,zero=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> c=<span class=\\"hljs-number\\">1</span>&lt;&lt;i\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> num <span class=\\"hljs-keyword\\">of</span> nums){\\n      <span class=\\"hljs-keyword\\">if</span>((num &amp; c) &gt;<span class=\\"hljs-number\\">0</span>)one++\\n      <span class=\\"hljs-keyword\\">else</span> zero++\\n    }\\n    res+=one*zero\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"total-hamming-distance","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u8fd9\u91cc\u4e3b\u8981\u662f <code>&gt;&gt;</code> \u548c <code>&amp;</code>\uff0c\u5b9e\u73b0\u5bf9\u6bcf\u4e00\u4e2a\u6570\u636e\u8fdb\u884c\u4f4d\u6570\u5904\u7406</p>\\n<p>1\u3001\u5bf9\u6bcf\u4e00\u4e2a\u6570\u636e\u8fdb\u884c\u53f3\u79fb i\u4f4d<code>nums[j] &gt;&gt; i</code> \uff0c\u5f97\u51fa k</p>\\n<p>2\u3001\u5bf9 k \u8fdb\u884c <code>k &amp; 1</code>\uff0c 1 \u7684\u4e8c\u8fdb\u5236\u662f<code>...00001</code>\uff0c\u56e0\u6b64\u53ef\u4ee5\u5224\u65ad\u51fa k \u7684\u6700\u540e1\u4f4d\u662f 1 \u8fd8\u662f 0\uff0c\u6240\u4ee5<code>binCount</code>\u5c31\u662f\u6700\u540e\u4e00\u4f4d\u4e3a1\u7684\u6570\u91cf</p>\\n<p>3\u3001<code>binCount*(nums.length-binCount)</code> \uff0c\u5176\u4e2d<code>nums.length-binCount</code>\u6307\u6700\u540e\u4e00\u4f4d\u662f0\u7684\u6570\u91cf\uff0c\u56e0\u6b64<code>1\u7684\u6570\u91cf*0\u7684\u6570\u91cf</code>\uff0c\u4e5f\u5c31\u662f\u5b83\u4eec\u80fd\u7ec4\u5408\u7684\u6d77\u660e\u8ddd\u79bb</p>\\n","content":"<p>\u4e24\u4e2a\u6574\u6570\u7684\xa0<a href=\\"https://baike.baidu.com/item/%E6%B1%89%E6%98%8E%E8%B7%9D%E7%A6%BB/475174?fr=aladdin\\">\u6c49\u660e\u8ddd\u79bb</a> \u6307\u7684\u662f\u8fd9\u4e24\u4e2a\u6570\u5b57\u7684\u4e8c\u8fdb\u5236\u6570\u5bf9\u5e94\u4f4d\u4e0d\u540c\u7684\u6570\u91cf\u3002</p>\\n\\n<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4 <code>nums</code>\uff0c\u8bf7\u4f60\u8ba1\u7b97\u5e76\u8fd4\u56de <code>nums</code> \u4e2d\u4efb\u610f\u4e24\u4e2a\u6570\u4e4b\u95f4\u6c49\u660e\u8ddd\u79bb\u7684\u603b\u548c\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [4,14,2]\\n<strong>\u8f93\u51fa\uff1a</strong>6\\n<strong>\u89e3\u91ca\uff1a</strong>\u5728\u4e8c\u8fdb\u5236\u8868\u793a\u4e2d\uff0c4 \u8868\u793a\u4e3a 0100 \uff0c14 \u8868\u793a\u4e3a 1110 \uff0c2\u8868\u793a\u4e3a 0010 \u3002\uff08\u8fd9\u6837\u8868\u793a\u662f\u4e3a\u4e86\u4f53\u73b0\u540e\u56db\u4f4d\u4e4b\u95f4\u5173\u7cfb\uff09\\n\u6240\u4ee5\u7b54\u6848\u4e3a\uff1a\\nHammingDistance(4, 14) + HammingDistance(4, 2) + HammingDistance(14, 2) = 2 + 2 + 2 = 6\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [4,14,4]\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= nums.length <= 10<sup>5</sup></code></li>\\n\\t<li><code>0 <= nums[i] <= 10<sup>9</sup></code></li>\\n</ul>\\n","title":"477. \u6c49\u660e\u8ddd\u79bb\u603b\u548c","relatedTags":["\u4f4d\u8fd0\u7b97"],"difficult":"Middle","lang":["javascript"],"uniqueID":"477"}')}}]);